import java.io.*;

public class SecureCommandExecutionExample {

    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String userInput = br.readLine();

            // Sanitize user input to prevent command injection
            userInput = userInput.replaceAll("[^\\w.-]", "");

            ProcessBuilder pb = new ProcessBuilder("ping", userInput);
            pb.redirectErrorStream(true);
            Process proc = pb.start();

            BufferedReader inputReader = new BufferedReader(new InputStreamReader(proc.getInputStream()));
            String line;
            while ((line = inputReader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            System.out.println("An error occurred: " + e.getMessage());
        }
    }
}

